srcs/main.c (ft_check_args)<pre><code>static void ft_check_args(int argc, char **argv)
{
    int len;

    if (argc != 2)
        ft_error("Usage: ./cub3D &lt;map.cub&gt;");
    len = ft_strlen(argv[1]);
    if (len &lt; 5
        || ft_strncmp(argv[1] + len - 4, ".cub", 4) != 0)
        ft_error("Invalid file extension, expected .cub");
}
</code></pre> <p>拡張子チェックを忘れない</p> <p>評価では 「<code>.txt</code> を渡したらどうなる？」「引数 0 個ならどうなる？」 が必ず確認されます。 <code>argc != 2</code> と末尾 <code>.cub</code> の 2 つで弾くのが最小要件です。</p>

srcs/main.c (ft_close_window)<pre><code>static int ft_close_window(t_game *game)
{
    ft_cleanup(game);
    exit(0);
    return (0);
}
</code></pre> <p>× ボタンを <code>mlx_hook(win, 17, ...)</code> で拾わないと</p> <p>miniLibX は × ボタンを 自動では処理しない ので、ウィンドウが消えてもプロセスは生き続けます。 そのままだと メモリリーク で評価終了。<code>17 = DestroyNotify</code> を必ず登録します。</p>

parse.c (ft_parse)<pre><code>void ft_parse(char *path, t_config *config)
{
    char  *content;
    char **lines;

    ft_bzero(config, sizeof(t_config));
    content = ft_read_file(path);
    lines = ft_split_lines(content);
    free(content);
    if (!lines)
        ft_error("Memory allocation failed");
    ft_set_errctx(config, lines);
    ft_process_lines(lines, config);
    ft_validate_map(config);
    ft_set_errctx(NULL, NULL);
    ft_free_lines(lines);
}
</code></pre>

raycaster.c (init_step)<pre><code>static void ft_init_step(t_game *game, t_ray *ray)
{
    if (ray-&gt;dir.x &lt; 0)
    {
        ray-&gt;step.x = -1;           // 左に進む
        ray-&gt;side_dist.x = (game-&gt;player.pos.x - ray-&gt;map_pos.x)
            * ray-&gt;delta_dist.x;
    }
    else
    {
        ray-&gt;step.x = 1;            // 右に進む
        ray-&gt;side_dist.x = (ray-&gt;map_pos.x + 1.0 - game-&gt;player.pos.x)
            * ray-&gt;delta_dist.x;
    }
    if (ray-&gt;dir.y &lt; 0)
    {
        ray-&gt;step.y = -1;           // 上に進む
        ray-&gt;side_dist.y = (game-&gt;player.pos.y - ray-&gt;map_pos.y)
            * ray-&gt;delta_dist.y;
    }
    else
    {
        ray-&gt;step.y = 1;            // 下に進む
        ray-&gt;side_dist.y = (ray-&gt;map_pos.y + 1.0 - game-&gt;player.pos.y)
            * ray-&gt;delta_dist.y;
    }
}
</code></pre>

raycaster.c (dda)<pre><code>static void ft_dda(t_game *game, t_ray *ray)
{
    int hit;

    hit = 0;
    while (!hit)
    {
        if (ray-&gt;side_dist.x &lt; ray-&gt;side_dist.y)
        {
            ray-&gt;side_dist.x += ray-&gt;delta_dist.x;
            ray-&gt;map_pos.x += ray-&gt;step.x;
            ray-&gt;side = 0;  // X 壁に当たった
        }
        else
        {
            ray-&gt;side_dist.y += ray-&gt;delta_dist.y;
            ray-&gt;map_pos.y += ray-&gt;step.y;
            ray-&gt;side = 1;  // Y 壁に当たった
        }
        if (ray-&gt;map_pos.x &lt; 0 || ray-&gt;map_pos.x &gt;= game-&gt;config.map_w
            || ray-&gt;map_pos.y &lt; 0 || ray-&gt;map_pos.y &gt;= game-&gt;config.map_h)
            break ;
        if (game-&gt;config.map[ray-&gt;map_pos.y][ray-&gt;map_pos.x] == '1')
            hit = 1;
    }
}
</code></pre>

raycaster.c (init_ray_dir)<pre><code>static void ft_init_ray_dir(t_game *game, int x, t_ray *ray)
{
    double camera_x;

    camera_x = 2.0 * x / (double)WIN_W - 1.0;
    ray-&gt;dir.x = game-&gt;player.dir.x + game-&gt;player.plane.x * camera_x;
    ray-&gt;dir.y = game-&gt;player.dir.y + game-&gt;player.plane.y * camera_x;
    ray-&gt;map_pos.x = (int)game-&gt;player.pos.x;
    ray-&gt;map_pos.y = (int)game-&gt;player.pos.y;
    if (ray-&gt;dir.x == 0)
        ray-&gt;delta_dist.x = 1e30;  // div by 0 対策
    else
        ray-&gt;delta_dist.x = fabs(1.0 / ray-&gt;dir.x);
    if (ray-&gt;dir.y == 0)
        ray-&gt;delta_dist.y = 1e30;
    else
        ray-&gt;delta_dist.y = fabs(1.0 / ray-&gt;dir.y);
}
</code></pre>

raycaster.c (calc_wall_dist)<pre><code>static void ft_calc_wall_dist(t_game *game, t_ray *ray)
{
    if (ray-&gt;side == 0)
    {
        ray-&gt;perp_wall_dist = ray-&gt;side_dist.x - ray-&gt;delta_dist.x;
        ray-&gt;wall_x = game-&gt;player.pos.y
            + ray-&gt;perp_wall_dist * ray-&gt;dir.y;
    }
    else
    {
        ray-&gt;perp_wall_dist = ray-&gt;side_dist.y - ray-&gt;delta_dist.y;
        ray-&gt;wall_x = game-&gt;player.pos.x
            + ray-&gt;perp_wall_dist * ray-&gt;dir.x;
    }
    ray-&gt;wall_x -= floor(ray-&gt;wall_x);
    if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &gt; 0)
        ray-&gt;tex_id = TEX_EA;
    else if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &lt;= 0)
        ray-&gt;tex_id = TEX_WE;
    else if (ray-&gt;side == 1 &amp;&amp; ray-&gt;dir.y &gt; 0)
        ray-&gt;tex_id = TEX_SO;
    else
        ray-&gt;tex_id = TEX_NO;
}
</code></pre>

draw_column.c (calc_draw_params)<pre><code>static void ft_calc_draw_params(t_ray *ray, t_img *tex, t_draw *d)
{
    // 壁の高さ = 画面高さ / 距離 (距離が近いほど高く)
    d-&gt;line_h = (int)(WIN_H / ray-&gt;perp_wall_dist);
    d-&gt;draw_start = -d-&gt;line_h / 2 + WIN_H / 2;
    d-&gt;draw_end = d-&gt;line_h / 2 + WIN_H / 2;
    if (d-&gt;draw_start &lt; 0)
        d-&gt;draw_start = 0;
    if (d-&gt;draw_end &gt;= WIN_H)
        d-&gt;draw_end = WIN_H - 1;
    // wall_x (0〜1) を tex-&gt;width 倍してテクスチャ X 座標に
    d-&gt;tex_x = (int)(ray-&gt;wall_x * tex-&gt;width);
    // 光線の向きに合わせてテクスチャを左右反転
    if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &gt; 0)
        d-&gt;tex_x = tex-&gt;width - d-&gt;tex_x - 1;
    if (ray-&gt;side == 1 &amp;&amp; ray-&gt;dir.y &lt; 0)
        d-&gt;tex_x = tex-&gt;width - d-&gt;tex_x - 1;
    // テクスチャ Y 方向のステップ幅
    d-&gt;step = 1.0 * tex-&gt;height / d-&gt;line_h;
    d-&gt;tex_pos = (d-&gt;draw_start - WIN_H / 2 + d-&gt;line_h / 2) * d-&gt;step;
}
</code></pre>

draw_column.c (draw_column)<pre><code>void ft_draw_column(t_game *game, int x, t_ray *ray)
{
    t_draw  d;
    t_img   *tex;
    int     y;
    int     tex_y;
    int     color;

    tex = &amp;game-&gt;tex[ray-&gt;tex_id];
    ft_calc_draw_params(ray, tex, &amp;d);
    ft_draw_ceiling(game, x, d.draw_start);
    y = d.draw_start;
    while (y &lt;= d.draw_end)
    {
        tex_y = (int)d.tex_pos;
        if (tex_y &gt;= tex-&gt;height)
            tex_y = tex-&gt;height - 1;
        d.tex_pos += d.step;
        color = ft_get_texel(tex, d.tex_x, tex_y);
        ft_put_pixel(&amp;game-&gt;frame, x, y, color);
        y++;
    }
    ft_draw_floor(game, x, d.draw_end + 1);
}
</code></pre>

draw_column.c (ceiling/floor)<pre><code>static void ft_draw_ceiling(t_game *game, int x, int end)
{
    int y;

    y = 0;
    while (y &lt; end)
    {
        ft_put_pixel(&amp;game-&gt;frame, x, y, game-&gt;config.ceiling.hex);
        y++;
    }
}

static void ft_draw_floor(t_game *game, int x, int start)
{
    int y;

    y = start;
    while (y &lt; WIN_H)
    {
        ft_put_pixel(&amp;game-&gt;frame, x, y, game-&gt;config.floor.hex);
        y++;
    }
}
</code></pre>

