srcs/parser/parse_map.c<pre><code>// ❌ 修正前
static int ft_map_line_count(char **lines, int start)
{
    int count;
    int last_nonempty;
    int i;

    count = 0;
    last_nonempty = start;
    i = start;
    while (lines[i])  // ← ファイル最後まで走査
    {
        if (lines[i][0] != '\0')
            last_nonempty = i;
        i++;
    }
    count = last_nonempty - start + 1;
    return (count);
}

// ✅ 修正後
static int ft_map_line_count(char **lines, int start)
{
    int i;

    i = start;
    // 最初の空行まで進んだら終了
    while (lines[i] &amp;&amp; lines[i][0] != '\0')
        i++;
    return (i - start);
}
</code></pre>

