{
    char    **parts;
    int     r, g, b;

    parts = ft_split(line, ',');
    if (ft_count(parts) != 3)
        return (ft_perr(config, "Invalid color format"));
    r = ft_atoi(parts[0]);
    g = ft_atoi(parts[1]);
    b = ft_atoi(parts[2]);
    ft_free_split(parts);
    if (r &lt; 0 || r &gt; 255 || g &lt; 0 || g &gt; 255 || b &lt; 0 || b &gt; 255)
        return (ft_perr(config, "Color out of range"));
    *color = (r &lt;&lt; 16) | (g &lt;&lt; 8) | b;
    return (0);
}
</code></pre>

