    if (y == 0 || x == 0 || y == h - 1)
        return (0);
    if (x &gt;= (int)ft_strlen(map[y]) - 1)
        return (0);
    char neighbors[4] = { map[y-1][x], map[y+1][x], map[y][x-1], map[y][x+1] };
